  const M = wd.__mh
  if (wd.__fresh) { delete wd.__fresh; M.px = 0; M.pz = 0 }
  const pdt = Math.min(dt, 0.05)

  const tx = ((wd.mouse_x ?? 256) - 256) / 256
  const ty = ((wd.mouse_y ?? 256) - 256) / 256
  M.mx += (tx - M.mx) * Math.min(1, pdt * 4)
  M.my += (ty - M.my) * Math.min(1, pdt * 4)

  // move along where you are LOOKING (yaw matches the shader: forward = (sin,cos))
  const yaw = M.mx * 0.55
  const fwd = [Math.sin(yaw), Math.cos(yaw)]
  const rgt = [Math.cos(yaw), -Math.sin(yaw)]
  const spd = (wd.key_shift ? 4.4 : 2.6) * pdt
  let dx = 0, dz = 0
  if (wd.key_w || wd.key_up) { dx += fwd[0] * spd; dz += fwd[1] * spd }
  if (wd.key_s || wd.key_down) { dx -= fwd[0] * spd; dz -= fwd[1] * spd }
  if (wd.key_d) { dx += rgt[0] * spd; dz += rgt[1] * spd }
  if (wd.key_a) { dx -= rgt[0] * spd; dz -= rgt[1] * spd }
  M.px += dx; M.pz += dz
  // stay on the walkway — the columns stand at |x|=2.2, the gold hugs the walls
  M.px = Math.max(-1.5, Math.min(1.5, M.px))

  // ── the dragon holds the end of the hall, always just out of reach ──
  const dragonZ = M.pz + 13.0

  // ── the fireball: SPACE or CLICK hurls it down your gaze ──
  if (!wd.__fb) wd.__fb = { on: 0, x: 0, y: 1.4, z: 0, dx: 0, dy: 0, dz: 1, life: 0, boom: 0, roar: 0 }
  const F = wd.__fb
  const pitch = -M.my * 0.30 + 0.02
  if (sim.edge('mh-cast', !!(wd.mouse_down || wd.key_space)) && !F.on) {
    F.on = 1; F.life = 2.4
    F.x = M.px; F.y = 1.35; F.z = M.pz + 0.3
    const len = Math.hypot(fwd[0], pitch, fwd[1]) || 1
    F.dx = fwd[0] / len; F.dy = pitch / len; F.dz = fwd[1] / len
    wd.__play_sound = [
      { frequency: 140, duration: 0.3, volume: 0.5, type: 'sawtooth' },
      { frequency: 620, duration: 0.12, volume: 0.22, type: 'triangle' },
    ]
  }
  if (F.on) {
    const v = 11.0
    F.x += F.dx * v * pdt; F.y += F.dy * v * pdt; F.z += F.dz * v * pdt
    F.life -= pdt
    const nearDragon = Math.hypot(F.x - 0, F.y - 1.6, F.z - dragonZ) < 2.6
    // walls, floor, ceiling, the dragon, or plain old time end the flight
    if (F.life <= 0 || F.y < 0.06 || F.y > 3.5 || Math.abs(F.x) > 2.05 || nearDragon) {
      F.on = 0; F.boom = 1
      if (nearDragon) {
        F.roar = 1
        wd.__play_sound = [
          { frequency: 55, duration: 0.8, volume: 0.7, type: 'square' },
          { frequency: 82, duration: 0.6, volume: 0.4, type: 'sawtooth' },
          { frequency: 38, duration: 1.0, volume: 0.5, type: 'sine' },
        ]
      } else {
        wd.__play_sound = [
          { frequency: 70, duration: 0.45, volume: 0.6, type: 'square' },
          { frequency: 210, duration: 0.18, volume: 0.2, type: 'triangle' },
        ]
      }
    }
  }
  F.boom = Math.max(0, F.boom - pdt * 2.2)
  F.roar = Math.max(0, F.roar - pdt * 0.8)

  wd.gpuUniforms = [M.mx, M.my, M.px, M.pz, F.on, F.x, F.y, F.z, F.life, F.boom, dragonZ, F.roar]
} catch (e) { /* the hall walks on */ }

visualTypes.wgsl:
// ── THE GILDED HALL v3: smoother march, a fireball in the hand, a dragon at the end. ──
// The frame cost was shadows: up to 6 rays × 8 steps per pixel. Now ONE shadow ray
// (nearest flame, 6 steps); the map's noise dropped to 2 octaves; AO 2 taps;
// the floor mirror probes 5 steps and only within 9 units. The dragon lives
// behind a bounding sphere — far pixels pay one length() for it.
fn mh_h3(p: vec3f) -> f32 { return fract(sin(dot(p, vec3f(127.1, 311.7, 74.7))) * 43758.5453); }
fn mh_n3(p: vec3f) -> f32 {
  let i = floor(p); let f = fract(p);
  let u = f * f * (3.0 - 2.0 * f);
  return mix(
    mix(mix(mh_h3(i), mh_h3(i + vec3f(1.0, 0.0, 0.0)), u.x),
        mix(mh_h3(i + vec3f(0.0, 1.0, 0.0)), mh_h3(i + vec3f(1.0, 1.0, 0.0)), u.x), u.y),
    mix(mix(mh_h3(i + vec3f(0.0, 0.0, 1.0)), mh_h3(i + vec3f(1.0, 0.0, 1.0)), u.x),
        mix(mh_h3(i + vec3f(0.0, 1.0, 1.0)), mh_h3(i + vec3f(1.0, 1.0, 1.0)), u.x), u.y), u.z);
}
fn mh_fbm(p: vec3f) -> f32 {
  return mh_n3(p) * 0.62 + mh_n3(p * 2.13) * 0.38;
}
fn mh_ell(p: vec3f, r: vec3f) -> f32 {
  let k0 = length(p / r);
  let k1 = length(p / (r * r));
  return k0 * (k0 - 1.0) / max(k1, 0.0001);
}
fn mh_seg(p: vec3f, a: vec3f, b: vec3f, r: f32) -> f32 {
  let pa = p - a; let ba = b - a;
  let h = clamp(dot(pa, ba) / dot(ba, ba), 0.0, 1.0);
  return length(pa - ba * h) - r;
}

var<private> mh_coarse: bool = false;
var<private> mh_t: f32 = 0.0;
var<private> mh_roar: f32 = 0.0;
var<private> mh_dc: vec3f = vec3f(0.0);   // the dragon's skull center, world space

// ── THE DRAGON: skull, snout, brows, cheeks, hinged jaw, fangs, horns, burning
// eyes, a neck that falls away into the dark. materials: 4 hide · 5 eye · 6 bone
fn mh_dragon(p0: vec3f) -> vec2f {
  let q0 = p0 - mh_dc;
  // bounding sphere (covers head + horns + the neck's reach) — the cheap gate
  let db = length(q0 - vec3f(0.0, -0.6, 1.2)) - 4.3;
  if (db > 0.5) { return vec2f(db, 4.0); }
  // it faces the walker: snout points down -world-z
  let s = vec3f(q0.x, q0.y, -q0.z);
  let m = vec3f(abs(s.x), s.y, s.z);
  var d = mh_ell(s - vec3f(0.0, 0.15, -0.2), vec3f(0.85, 0.72, 1.05));           // skull
  d = opSmoothUnion(d, mh_ell(s - vec3f(0.0, -0.05, 0.95), vec3f(0.48, 0.40, 0.90)), 0.28);  // snout
  d = opSmoothUnion(d, mh_ell(m - vec3f(0.34, 0.44, 0.30), vec3f(0.30, 0.17, 0.45)), 0.15);  // brow ridges
  d = opSmoothUnion(d, mh_ell(m - vec3f(0.62, -0.05, 0.15), vec3f(0.28, 0.30, 0.42)), 0.22); // cheekbones
  var mat = 4.0;
  // the jaw, hinged behind the chin — a roar throws it wide
  let ja = 0.20 + mh_roar * 0.6 + 0.05 * sin(mh_t * 0.9);
  var j = s - vec3f(0.0, -0.30, 0.10);
  let ca = cos(ja); let sa = sin(ja);
  j = vec3f(j.x, j.y * ca - j.z * sa, j.y * sa + j.z * ca);
  d = opSmoothUnion(d, mh_ell(j - vec3f(0.0, -0.06, 0.80), vec3f(0.38, 0.15, 0.80)), 0.10);
  // the neck, falling away into the smoke
  d = opSmoothUnion(d, mh_seg(s, vec3f(0.0, -0.15, -0.8), vec3f(0.0, -2.1, -3.2), 0.78), 0.45);
  // horns: two swept segments a side, thick then fine
  var dh = mh_seg(m, vec3f(0.40, 0.52, -0.20), vec3f(0.98, 1.15, -1.05), 0.13);
  dh = min(dh, mh_seg(m, vec3f(0.98, 1.15, -1.05), vec3f(1.16, 1.72, -1.85), 0.065));
  // fangs on the upper rim, canines heavier
  let u = m - vec3f(0.0, -0.33, 0.0);
  let cellx = clamp(round(u.x / 0.13), 0.0, 3.0);
  var dt2 = mh_ell(vec3f(u.x - cellx * 0.13, (u.y + 0.06) * 0.5, u.z - 1.30), vec3f(0.030, 0.10, 0.045));
  dt2 = min(dt2, mh_ell(vec3f(m.x - 0.34, (m.y + 0.30) * 0.45, m.z - 1.05), vec3f(0.05, 0.16, 0.07)));
  dh = min(dh, dt2);
  if (dh < d) { d = dh; mat = 6.0; }
  // the eyes, set burning
  let de = length(m - vec3f(0.35, 0.28, 0.62)) - 0.14;
  if (de < d) { d = de; mat = 5.0; }
  // nostrils (carved out)
  d = max(d, -(length(m - vec3f(0.16, 0.06, 1.78)) - 0.07));
  return vec2f(d, mat);
}

// the hall, repeated forever down z. returns (distance, material)
// materials: 1 marble · 2 gold · 3 ceiling/plaster · 4 hide · 5 eye · 6 bone
fn mh_map(p0: vec3f) -> vec2f {
  var p = p0;
  let cz = floor(p.z / 4.0);
  p.z = p.z - (cz + 0.5) * 4.0;
  var d = p.y;                       // the floor
  var m = 1.0;
  // columns, both sides: fluted shafts with entasis, base and capital
  for (var s2 = 0; s2 < 2; s2++) {
    let sx = select(-2.2, 2.2, s2 == 1);
    let q = vec2f(p.x - sx, p.z);
    let r = 0.34 + 0.016 * sin(p.y * 1.05 + 1.2);
    var dc = length(q) - r;
    let ang = atan2(q.y, q.x);
    dc += 0.011 * abs(sin(ang * 10.0));            // twenty flutes
    dc = max(dc, p.y - 3.3);
    let db = max(max(abs(p.x - sx) - 0.52, abs(p.z) - 0.52), p.y - 0.26);
    let dk = max(max(abs(p.x - sx) - 0.55, abs(p.z) - 0.55), abs(p.y - 3.32) - 0.16);
    let dcol = min(dc, min(db, dk));
    if (dcol < d) { d = dcol; m = 1.0; }
  }
  // the ceiling: coffered — beams every half-cell
  let dce = 3.62 - p.y + 0.06 * step(abs(fract(p.z * 0.5 + 0.25) - 0.5), 0.06);
  if (dce < d) { d = dce; m = 3.0; }
  // the hoard: mounds of gold hugging the walls, different every cell
  for (var g = 0; g < 2; g++) {
    let fg = f32(g);
    let h1 = mh_h3(vec3f(cz, fg, 3.0));
    let h2 = mh_h3(vec3f(cz, fg, 9.0));
    if (h1 < 0.25) { continue; }                    // some bays stand empty
    let gx = select(-1.42, 1.42, g == 1);
    let c = vec3f(gx, -0.15, (h1 - 0.5) * 2.2);
    var dg = length((p - c) * vec3f(1.0, 1.75, 0.9)) - (0.8 + 0.35 * h2);
    if (!mh_coarse) { dg += 0.05 * mh_fbm(p * 7.0) - 0.025; }   // lumpiness (skipped on shadow/ao/reflection)
    dg = max(dg, -p.y - 0.01);
    if (dg < d) { d = dg; m = 2.0; }
    // spill: a low apron of scattered coins reaching the walkway
    var ds = length((p - vec3f(gx * 0.72, -0.3, c.z)) * vec3f(1.0, 3.4, 1.0)) - (0.55 + 0.2 * h2);
    if (!mh_coarse) { ds += 0.045 * mh_fbm(p * 9.0 + 5.0) - 0.02; }
    ds = max(ds, -p.y - 0.01);
    if (ds < d) { d = ds; m = 2.0; }
  }
  // the dragon holds the end of the hall — world space, not the repeated cell
  let dd = mh_dragon(p0);
  if (dd.x < d) { d = dd.x; m = dd.y; }
  return vec2f(d, m);
}

fn mh_norm(p: vec3f) -> vec3f {
  mh_coarse = true;
  let e = 0.004;
  let n = normalize(vec3f(
    mh_map(p + vec3f(e, 0.0, 0.0)).x - mh_map(p - vec3f(e, 0.0, 0.0)).x,
    mh_map(p + vec3f(0.0, e, 0.0)).x - mh_map(p - vec3f(0.0, e, 0.0)).x,
    mh_map(p + vec3f(0.0, 0.0, e)).x - mh_map(p - vec3f(0.0, 0.0, e)).x));
  mh_coarse = false;
  return n;
}

fn mh_shadow(ro: vec3f, rd: vec3f, maxT: f32) -> f32 {
  mh_coarse = true;
  var res = 1.0; var t2 = 0.06;
  for (var i = 0; i < 6; i++) {
    if (t2 >= maxT) { break; }
    let h = mh_map(ro + rd * t2).x;
    res = min(res, 9.0 * h / t2);
    t2 += max(h, 0.05);
    if (res < 0.02) { break; }
  }
  mh_coarse = false;
  return clamp(res, 0.0, 1.0);
}

fn mh_ao(p: vec3f, n: vec3f) -> f32 {
  mh_coarse = true;
  var occ = 0.0; var w = 0.72;
  for (var i = 1; i <= 2; i++) {
    let h = 0.09 * f32(i);
    occ += (h - mh_map(p + n * h).x) * w;
    w *= 0.55;
  }
  mh_coarse = false;
  return clamp(1.0 - 1.6 * occ, 0.0, 1.0);
}

// one torch flame's contribution — warm, flickering, inverse-square.
// the shadow term arrives from outside: only the nearest flame pays for a real ray.
fn mh_torch(p: vec3f, n: vec3f, v: vec3f, lp: vec3f, t: f32, seed: f32, specK: f32, sh: f32) -> vec3f {
  let L = lp - p;
  let dist = length(L);
  let l = L / max(dist, 0.001);
  let flick = 0.82 + 0.18 * sin(t * 9.0 + seed * 17.0) * sin(t * 5.3 + seed * 7.0);
  let atten = flick * 6.0 / (1.0 + dist * dist * 0.55);
  let dif = clamp(dot(n, l), 0.0, 1.0);
  var c = vec3f(1.0, 0.55, 0.22) * dif * atten * sh;
  let r = reflect(-l, n);
  let spec = pow(clamp(dot(r, v), 0.0, 1.0), mix(14.0, 42.0, specK));
  c += mix(vec3f(0.9, 0.85, 0.8), vec3f(1.1, 0.75, 0.30), specK) * spec * atten * sh * mix(0.35, 2.6, specK);
  return c;
}

fn visual_mon_hall(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let t = time;
  let mx = uni(0);
  let my = uni(1);
  mh_t = t;
  mh_roar = uni(11);
  // the dragon sways at its anchor, and a roar lunges it up the hall
  mh_dc = vec3f(
    sin(t * 0.5) * 0.35,
    1.62 + sin(t * 0.83) * 0.12,
    uni(10) - mh_roar * 1.1);

  // ── the walk: steady pace, a breath of bob, the head turns with the mouse ──
  let walk = uni(3);
  let ro = vec3f(uni(2), 1.5 + sin(t * 1.9) * 0.022, walk);
  let yaw = mx * 0.55;
  let pitch = -my * 0.30 + 0.02;
  var rd = normalize(vec3f(uv.x * 0.9, -uv.y * 0.9 + pitch, 1.0));
  let cy = cos(yaw); let sy = sin(yaw);
  rd = vec3f(rd.x * cy + rd.z * sy, rd.y, -rd.x * sy + rd.z * cy);

  // ── march ──
  var t2 = 0.02; var mat = 0.0; var hitP = ro;
  for (var i = 0; i < 52; i++) {
    let h = mh_map(ro + rd * t2);
    if (h.x < 0.0016 * t2 + 0.0008) { mat = h.y; hitP = ro + rd * t2; break; }
    t2 += h.x;
    if (t2 > 20.0) { break; }
  }

  let fbOn = uni(4);
  let fbP = vec3f(uni(5), uni(6), uni(7));
  let boom = uni(9);

  var col = vec3f(0.020, 0.014, 0.010);   // the dark the hall recedes into
  if (mat > 4.5 && mat < 5.5) {
    // the eyes burn on their own — no lamp lights them, none needs to
    let pulse = 1.3 + 3.5 * mh_roar + 0.25 * sin(t * 3.0 + 1.7);
    col = vec3f(1.5, 0.48, 0.10) * pulse;
  } else if (mat > 0.5) {
    let n = mh_norm(hitP);
    let v = -rd;
    let ao = mh_ao(hitP, n);

    // ── material: albedo + how it throws light back ──
    var alb = vec3f(0.0);
    var specK = 0.0;
    var jit = 0.0;
    if (mat < 1.5) {
      // marble: warm white, veined, worn at the walkway's center
      let vein = mh_fbm(hitP * vec3f(2.1, 2.1, 1.2));
      alb = mix(vec3f(0.66, 0.63, 0.58), vec3f(0.38, 0.36, 0.35), smoothstep(0.52, 0.72, vein));
      alb *= 0.9 + 0.1 * mh_n3(hitP * 23.0);
      if (n.y > 0.9) { alb *= 0.86 + 0.14 * smoothstep(0.0, 1.1, abs(hitP.x)); }
    } else if (mat < 2.5) {
      // gold: coin facets — the normal is dithered so every coin catches its own light
      alb = vec3f(0.95, 0.66, 0.22) * (0.75 + 0.5 * mh_n3(hitP * 34.0));
      specK = 1.0; jit = 0.55;
    } else if (mat < 3.5) {
      alb = vec3f(0.16, 0.12, 0.09);      // coffered plaster, smoke-darkened
    } else if (mat < 4.5) {
      // dragonhide: dark scales in bands, lighter under the throat
      let n1 = mh_n3(hitP * vec3f(7.0, 7.0, 4.0));
      let n2 = mh_n3(hitP * vec3f(19.0, 19.0, 11.0));
      alb = mix(vec3f(0.09, 0.12, 0.08), vec3f(0.15, 0.19, 0.11), n1) * (0.72 + 0.55 * n2);
      alb = mix(alb, vec3f(0.30, 0.26, 0.17), clamp(-n.y, 0.0, 1.0) * 0.55);
      specK = 0.35; jit = 0.18;
    } else {
      alb = vec3f(0.60, 0.54, 0.42);      // horn and fang: old bone
      specK = 0.2;
    }

    // facet the normal AFTER albedo: gold glitters, hide reads as scales
    var ng = n;
    if (jit > 0.0) {
      let jitter = vec3f(mh_n3(hitP * 52.0) - 0.5, mh_n3(hitP * 52.0 + 11.0) - 0.5, mh_n3(hitP * 52.0 + 23.0) - 0.5);
      ng = normalize(n + jitter * jit);
    }

    // ── torchlight: sconces three cells deep — ONE real shadow ray (nearest flame) ──
    let cell = floor(hitP.z / 4.0);
    let nsx = select(-1.85, 1.85, hitP.x > 0.0);
    let nlp = vec3f(nsx, 2.5, (cell + 0.5) * 4.0);
    var shN = 1.0;
    {
      let Ln = nlp - hitP; let dn = length(Ln);
      shN = mh_shadow(hitP + n * 0.02, Ln / max(dn, 0.001), dn);
    }
    var lit = vec3f(0.0);
    for (var lz = -1; lz <= 1; lz++) {
      let zc = (cell + f32(lz) + 0.5) * 4.0;
      for (var s3 = 0; s3 < 2; s3++) {
        let sx = select(-1.85, 1.85, s3 == 1);
        let isN = lz == 0 && abs(sx - nsx) < 0.1;
        lit += mh_torch(hitP, ng, v, vec3f(sx, 2.5, zc), t, cell + f32(lz) + f32(s3) * 0.5, specK, select(1.0, shN, isN));
      }
    }
    // a cool thin skylight down the axis — so the hall reads even between torches
    lit += vec3f(0.10, 0.12, 0.16) * clamp(ng.y, 0.0, 1.0);
    // gold glows with the hoard's own bounced warmth
    lit += vec3f(0.30, 0.15, 0.04) * step(1.5, mat) * step(mat, 2.5) * clamp(-ng.y + 0.4, 0.0, 1.0);
    // the fireball is a lamp in flight
    if (fbOn > 0.5) {
      let L = fbP - hitP; let dfb = length(L); let l = L / max(dfb, 0.001);
      lit += vec3f(1.3, 0.62, 0.22) * clamp(dot(ng, l), 0.0, 1.0) * 5.0 / (1.0 + dfb * dfb * 0.6);
    }
    // the burst washes the hall for a heartbeat
    if (boom > 0.01) {
      let L = fbP - hitP; let dbm = length(L); let l = L / max(dbm, 0.001);
      lit += vec3f(1.4, 0.85, 0.40) * clamp(dot(ng, l), 0.0, 1.0) * boom * boom * 10.0 / (1.0 + dbm * dbm * 0.30);
    }
    // the dragon's mouth smoulders — brighter when it answers
    {
      let mp = mh_dc + vec3f(0.0, -0.35, -1.35);
      let L = mp - hitP; let dmt = length(L); let l = L / max(dmt, 0.001);
      lit += vec3f(1.2, 0.35, 0.08) * clamp(dot(ng, l), 0.0, 1.0) * (0.5 + 2.8 * mh_roar) / (1.0 + dmt * dmt * 0.5);
    }

    col = alb * lit * ao;

    // the floor mirrors the treasure: one cheap reflected probe, near only
    if (mat < 1.5 && n.y > 0.9 && t2 < 9.0) {
      let rr = reflect(rd, n);
      mh_coarse = true;
      var rt = 0.05; var rm = 0.0;
      for (var ri = 0; ri < 5; ri++) {
        let rh = mh_map(hitP + rr * rt);
        if (rh.x < 0.01) { rm = rh.y; break; }
        rt += rh.x;
        if (rt > 7.0) { break; }
      }
      mh_coarse = false;
      if (rm > 1.5 && rm < 2.5) { col += vec3f(0.55, 0.34, 0.10) * 0.30 * (1.0 / (1.0 + rt * rt * 0.4)); }
      else { col += vec3f(0.05, 0.05, 0.06) * 0.5 / (1.0 + rt * 0.8); }
    }
  }

  // ── the flames themselves, drawn in air after the surface ──
  {
    let cell0 = floor((ro.z + 2.0) / 4.0);
    for (var fz = 0; fz < 3; fz++) {
      let zc = (cell0 + f32(fz) + 0.5) * 4.0;
      for (var s3 = 0; s3 < 2; s3++) {
        let lp = vec3f(select(-1.85, 1.85, s3 == 1), 2.5, zc);
        let toL = lp - ro;
        let proj = dot(toL, rd);
        if (proj > 0.2 && proj < t2 + 0.5) {
          let perp = length(toL - rd * proj);
          let fl2 = 0.8 + 0.2 * sin(t * 8.0 + zc * 3.1 + f32(s3) * 9.0);
          col += vec3f(1.0, 0.55, 0.18) * exp(-perp * perp * 260.0) * fl2 * 1.6 / (1.0 + proj * proj * 0.20);
          col += vec3f(1.0, 0.7, 0.3) * exp(-perp * perp * 30.0) * fl2 * 0.10 / (1.0 + proj * proj * 0.20);
        }
      }
    }
  }
  // the fireball in flight: a hot core, a breathing halo
  if (fbOn > 0.5) {
    let toF = fbP - ro; let proj = dot(toF, rd);
    if (proj > 0.15 && proj < t2 + 0.4) {
      let perp = length(toF - rd * proj);
      let wob = 0.85 + 0.15 * sin(t * 24.0);
      col += vec3f(1.5, 0.75, 0.25) * exp(-perp * perp * 300.0) * 3.2 * wob;
      col += vec3f(1.2, 0.45, 0.12) * exp(-perp * perp * 26.0) * 0.35;
    }
  }
  // the burst: an expanding shell of light where it died
  if (boom > 0.01) {
    let toB = fbP - ro; let proj = clamp(dot(toB, rd), 0.0, t2);
    let dp = length(toB - rd * proj);
    let rsh = 0.35 + (1.0 - boom) * 1.9;
    col += vec3f(1.5, 0.9, 0.45) * boom * boom * 2.6 * exp(-(dp - rsh) * (dp - rsh) * 6.0);
  }

  // depth: warm smoke swallows the far hall (thinned so the dragon reads through)
  col = mix(col, vec3f(0.028, 0.018, 0.011), 1.0 - exp(-t2 * 0.062));
  // grade: gentle lift, grain, vignette
  col = pow(col, vec3f(0.85));
  col *= 0.97 + 0.06 * hash21(uv * 640.0 + fract(t) * 41.0);
  col *= 1.0 - 0.35 * pow(length(uv) * 0.72, 3.0);
  if (col.x != col.x || col.y != col.y || col.z != col.z) { col = vec3f(0.02); }
  return vec4f(clamp(col, vec3f(0.0), vec3f(30.0)), 1.0);
}
